#!/bin/bash

# Monitor de Progresso - Teste Massivo Nível 5
# Mostra gráfico visual do progresso em tempo real

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR/../.."

# Cores
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
RED='\033[0;31m'
BLUE='\033[0;34m'
CYAN='\033[0;36m'
NC='\033[0m' # No Color

echo "📊 MONITOR DE PROGRESSO - TESTE MASSIVO NÍVEL 5"
echo "=============================================="
echo ""

# Verificar se há run_id ativo
LATEST_RUN=$(ls -t test-results/NIVEL_5/ 2>/dev/null | head -1)

if [ -z "$LATEST_RUN" ]; then
  echo "❌ Nenhum teste em execução encontrado."
  echo "   Execute: ./scripts/teste-massivo-nivel-5/teste-massivo-nivel-5.sh"
  exit 1
fi

echo "🔍 Run ID: $LATEST_RUN"
echo ""

# Verificar logs
LOG_DIR="test-results/NIVEL_5/$LATEST_RUN/logs"
if [ ! -d "$LOG_DIR" ]; then
  echo "⏳ Teste iniciando..."
  exit 0
fi

# Fases do teste
FASES=(
  "FASE 0: Preflight"
  "FASE 1: Setup Massivo"
  "FASE 2: Pedidos Caos"
  "FASE 3: KDS Stress"
  "FASE 4: Task Extreme"
  "FASE 5: Estoque Cascata"
  "FASE 6: Multi-Dispositivo"
  "FASE 7: Time Warp"
  "FASE 8: Relatório Final"
)

