for fase in "${FASES[@]}"; do
  fase_clean=$(echo "$fase" | tr '[:upper:]' '[:lower:]' | sed 's/[^a-z0-9]/-/g')
  log_file=$(ls -t "$LOG_DIR"/test-n5-*-${fase_clean}*.log 2>/dev/null | head -1)
  
  if [ -z "$log_file" ]; then
    status="⏳ PENDENTE"
    color=$YELLOW
  elif grep -q "COMPLETA\|COMPLETE" "$log_file" 2>/dev/null; then
    status="✅ COMPLETA"
    color=$GREEN
  elif grep -q "FALHOU\|ERROR" "$log_file" 2>/dev/null; then
    status="❌ FALHOU"
    color=$RED
  else
    status="🔄 EM EXECUÇÃO"
    color=$CYAN
  fi
  
  printf "${color}%-40s %s${NC}\n" "$fase" "$status"
